const hodnota = collections['27afccc3-5cc6-40c3-845f-e8444b80f8f2']?.data?.[0]?.duchod; 
const vstup = variables['51b18477-0d15-47bb-8223-4d0a25c61e6a'];

if (hodnota === undefined || vstup === undefined) return [];

const pokryti = Math.min(hodnota, vstup);
const chybi = Math.max(0, vstup - hodnota);

return [
  {
    label: 'Pokrytí',
    data: [pokryti],
    backgroundColor: '#10B981', 
    borderRadius: {topLeft: 0, topRight: 0, bottomLeft: 15, bottomRight: 15},
    borderSkipped: false,
    barPercentage: 1.0,
    categoryPercentage: 1.0,
    stack: 'a'
  },
  {
    label: 'Chybí',
    data: [chybi],
    backgroundColor: '#F87171', 
    borderRadius: {topLeft: 15, topRight: 15, bottomLeft: 0, bottomRight: 0},
    borderSkipped: false,
    barPercentage: 1.0,
