// 1. Načtení hodnoty z proměnné
const birthDateValue = variables['ffb85e5f-cfe2-4a43-8b93-9447be8b3fa9'];

// 2. Kontrola, zda je proměnná vyplněná
if (!birthDateValue) return false;

const birthDate = new Date(birthDateValue);
const today = new Date();

// 3. Výpočet základního rozdílu let
let age = today.getFullYear() - birthDate.getFullYear();

// 4. Korekce věku (pokud ještě v tomto roce neměl narozeniny)
const monthDiff = today.getMonth() - birthDate.getMonth();
if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
    age--;
}

// 5. Podmínka: Věk je 60 nebo více
return age >= 60;

