if (duchodRaw !== undefined && prijemVariable !== undefined && datumNarozeni) {

    // --- VÝPOČET VĚKU A HORIZONTU ---
    const dnes = new Date();
    const nahrani = new Date(datumNarozeni);
    let vek = dnes.getFullYear() - nahrani.getFullYear();
    const m = dnes.getMonth() - nahrani.getMonth();
    if (m < 0 || (m === 0 && dnes.getDate() < nahrani.getDate())) { vek--; }

    const cilovyVek = 65;
    const horizontLet = cilovyVek - vek;

    // Pokud je uživatel starší než 65, vrátíme info o důchodu
    if (horizontLet <= 0) return "Již v důchodu";

    // --- URČENÍ ÚROKOVÉ SAZBY ---
    let rocniUrok = 0;
    // Ošetřeno pro děti a mladé: kdokoliv pod 35 let má nyní 8%
    if (vek < 35) {
        rocniUrok = 0.08;
    } else if (vek >= 35 && vek < 50) {
        rocniUrok = 0.07;
    } else if (vek >= 50 && vek < 60) {
        rocniUrok = 0.055;
    } else if (vek >= 60 && vek <= 65) {
        rocniUrok = 0.035;
    } else {
        rocniUrok = 0.03;
    }

    // --- LOGIKA "POTŘEBY" ---
    const mesicniRozdil = prijemVariable - duchodRaw;
    if (mesicniRozdil <= 0) return "Důchod postačuje";

    // Cílový kapitál (předpoklad pro 20 let renty, koeficient 0.7)
    const cilovaCastkaPotreba = mesicniRozdil * 12 * 20 * 0.7;

    // --- VÝPOČET DOPORUČENÉ INVESTICE ---
    const r = rocniUrok / 12;
    const n = horizontLet * 12;

    // Měsíční úložka (PMT)
    const doporucenaInvestice = cilovaCastkaPotreba * (r / (Math.pow(1 + r, n) - 1));

    // --- VÝPOČET FINÁLNÍHO KAPITÁLU ---
    const finalniKapital = doporucenaInvestice * ((Math.pow(1 + r, n) - 1) / r);

    return Math.round(finalniKapital).toLocaleString("cs-CZ") + " Kč";
}

return "Nezadáno";

