(async () => {
  const root = document.getElementById('print-root');
  if (!root) return alert('print-root nebyl nalezen');
  if (!window.html2canvas) return alert('html2canvas není načtený');
  if (!window.jspdf?.jsPDF) return alert('jsPDF není načtené');

  const { jsPDF } = window.jspdf;
  const pdf = new jsPDF('p', 'mm', 'a4');

  const pageW = 210;
  const pageH = 297;
  const margin = 10;
  const contentW = pageW - margin * 2;
  const contentH = pageH - margin * 2;

  // Najdi všechny tiskové bloky uvnitř print-root
  const items = Array.from(root.querySelectorAll('.print-item'));

  if (!items.length) {
    alert('V #print-root nejsou žádné .print-item bloky');
    return;
  }

  let firstPage = true;

  for (const item of items) {
    // klon jednoho bloku (bez zásahu do živého UI)
    const clone = item.cloneNode(true);

    // styl pro stabilní render
    clone.style.display = 'block';
    clone.style.width = root.getBoundingClientRect().width + 'px';
    clone.style.maxWidth = 'none';
    clone.style.minHeight = 'auto';
    clone.style.height = 'auto';
    clone.style.margin = '0';
    clone.style.background = '#fff';
    clone.style.opacity = '1';
    clone.style.filter = 'none';
    clone.style.transform = 'none';
    clone.style.position = 'fixed';
    clone.style.left = '0';
    clone.style.top = '0';
    clone.style.zIndex = '999999';

    // odstranění nulových canvasů (předchozí pád)
    clone.querySelectorAll('canvas').forEach(c => {
      const r = c.getBoundingClientRect();
      if ((c.width || 0) === 0 || (c.height || 0) === 0 || r.width === 0 || r.height === 0) {
        c.remove();
      }
    });

    document.body.appendChild(clone);

    try {
      const canvas = await html2canvas(clone, {
        scale: 2,
        useCORS: true,
        backgroundColor: '#ffffff',
        logging: false
      });

      const imgData = canvas.toDataURL('image/jpeg', 0.95);
      const imgW = contentW;
      const imgH = (canvas.height * imgW) / canvas.width;

      if (!firstPage) pdf.addPage();
      firstPage = false;

      // Pokud je blok vyšší než jedna stránka, rozřež jen tento blok
      let left = imgH;
      let y = margin;

      try {
        pdf.addImage(imgData, 'JPEG', margin, y, imgW, imgH);
      } catch (e) {
        console.error('addImage failed (first page of block):', e);
        continue; // přeskoč problémový blok, ať se export nezastaví
      }

      left -= contentH;

      while (left > 0) {
        y = margin - (imgH - left);
        pdf.addPage();
        try {
          pdf.addImage(imgData, 'JPEG', margin, y, imgW, imgH);
        } catch (e) {
          console.error('addImage failed (continuation page of block):', e);
          break;
        }
        left -= contentH;
      }
    } catch (e) {
      console.error('Blok selhal, přeskakuju:', e);
    } finally {
      clone.remove();
    }
  }

  pdf.save('Plan.pdf');
})();

