// 1. Získání dat
const duchodRaw = collections['27afccc3-5cc6-40c3-845f-e8444b80f8f2']?.data?.[0]?.duchod;
const prijemVariable = variables['51b18477-0d15-47bb-8223-4d0a25c61e6a'];
const datumNarozeni = variables['ffb85e5f-cfe2-4a43-8b93-9447be8b3fa9'];

if (duchodRaw !== undefined && prijemVariable !== undefined && datumNarozeni) {
    
    // --- VÝPOČET VĚKU A HORIZONTU ---
    const dnes = new Date();
    const nahrani = new Date(datumNarozeni);
    let vek = dnes.getFullYear() - nahrani.getFullYear();
    const m = dnes.getMonth() - nahrani.getMonth();
    if (m < 0 || (m === 0 && dnes.getDate() < nahrani.getDate())) { vek--; }

    const cilovyVek = 65;
    const horizontLet = cilovyVek - vek;

    if (horizontLet <= 0) return "Již v důchodu";

    // --- URČENÍ ÚROKOVÉ SAZBY ---
    let rocniUrok = 0;
    // Ošetřeno: Věk pod 35 let (včetně dětí) má vždy 8 %
    if (vek < 35) rocniUrok = 0.08;
    else if (vek >= 35 && vek < 50) rocniUrok = 0.07;
    else if (vek >= 50 && vek < 60) rocniUrok = 0.055;
    else if (vek >= 60 && vek <= 65) rocniUrok = 0.035;
    else rocniUrok = 0.03;

    // --- VÝPOČET CÍLOVÉHO KAPITÁLU ---
    const mesicniRozdil = prijemVariable - duchodRaw;
    if (mesicniRozdil <= 0) return "0 Kč";

    // Cílová částka pro 20 let renty
    const cilovaCastka = mesicniRozdil * 12 * 20 * 0.7;

    // --- VÝPOČET MĚSÍČNÍ INVESTICE (Anuita) ---
    // Vzorec: PMT = FV * (r / ((1 + r)^n - 1))
    const r = rocniUrok / 12; // měsíční úrok
    const n = horizontLet * 12; // počet měsíců
    
    const mesicniInvestice = cilovaCastka * (r / (Math.pow(1 + r, n) - 1));

    // Zaokrouhlení nahoru pro jistotu a formátování
    return "Měsíčně: " + Math.ceil(mesicniInvestice).toLocaleString("cs-CZ") + " Kč";
}

return "Nezadáno";

