const name = variables['a3fdc33d-c773-47bf-bfd6-a125db530196']; // Vstupní příjmení
if (!name || name.trim() === "") return "";

const trimmedName = name.trim();
const lowerName = trimmedName.toLowerCase();

// 1. Detekce žen (koncovky -ová, -á)
const isFemale = lowerName.endsWith('ová') || lowerName.endsWith('á');

if (isFemale) {
    // Pro ženy: paní + 1. pád (nemění se)
    return "paní " + trimmedName.charAt(0).toUpperCase() + trimmedName.slice(1);
} else {
    // Pro muže: pane + vokativ (5. pád)
    let vocative = trimmedName;
    const lastChar = lowerName.slice(-1);
    const lastTwoChars = lowerName.slice(-2);

    // SPECIÁLNÍ OPRAVA: Koncovka -o (Hnízdo -> pane Hnízdo)
    if (lastChar === 'o') {
        vocative = trimmedName; 
    } 
    // Koncovka -ek (Andrýsek -> Andrýsku)
    else if (lastTwoChars === 'ek') {
        vocative = trimmedName.slice(0, -2) + 'ku';
    } 
    // Koncovka -a (Svoboda -> Svobodo)
    else if (lastChar === 'a') {
        vocative = trimmedName.slice(0, -1) + 'o';
    } 
    // Měkké souhlásky (Babiš -> Babiši, Černý -> Černý)
    else if (['š', 'č', 'ř', 'c', 'j', 'z', 'ď', 'ť', 'ň'].includes(lastChar)) {
        vocative = trimmedName + 'i';
    } 
    // Přídavná jména (Novotný, Šťastný)
    else if (['ý', 'í'].includes(lastChar)) {
        vocative = trimmedName;
    } 
    // Ostatní (Novák -> Nováku, Andrýs -> Andrýsu)
    else {
        vocative = trimmedName + 'u';
    }

    return "pane " + vocative.charAt(0).toUpperCase() + vocative.slice(1);
}

