// 1. Vstupy
const targetAmount = Number(variables['708e547d-0263-4f29-9d79-751813f6657d']?.['amount']) || 0;
const years = Number(variables['708e547d-0263-4f29-9d79-751813f6657d']?.['horizon']) || 0;

// 2. Parametry
const inflation = 0.03; 
let annualReturn = (years <= 3) ? 0.03 : (years <= 7) ? 0.05 : 0.08;

// 3. Výpočet
const realAnnualReturn = (1 + annualReturn) / (1 + inflation) - 1;
const realMonthlyRate = realAnnualReturn / 12;
const totalMonths = years * 12;

let monthlyPayment = (totalMonths > 0 && realMonthlyRate > 0) 
    ? targetAmount * (realMonthlyRate / (Math.pow(1 + realMonthlyRate, totalMonths) - 1))
    : (totalMonths > 0) ? targetAmount / totalMonths : 0;

const nominalMonthlyRate = annualReturn / 12;
let totalFutureValue = (totalMonths > 0 && nominalMonthlyRate > 0)
    ? monthlyPayment * ((Math.pow(1 + nominalMonthlyRate, totalMonths) - 1) / nominalMonthlyRate)
    : monthlyPayment * totalMonths;

const totalDeposits = Math.round(monthlyPayment * totalMonths);
const totalInterest = Math.round(totalFutureValue - totalDeposits);

// 4. Formát dat pro STACKED BAR (každá část je samostatný objekt)
return [
    {
        "Typ": "Vklady",
        "Hodnota": totalDeposits,
        "Skupina": "Moje investice"
    },
    {
        "Typ": "Zhodnocení",
        "Hodnota": totalInterest > 0 ? totalInterest : 0,
        "Skupina": "Moje investice"
    }
];

