    vek = t.getFullYear() - b.getFullYear();
    const m = t.getMonth() - b.getMonth();
    if (m < 0 || (m === 0 && t.getDate() < b.getDate())) vek--;
}

if (vek === null || (ulozka === 0 && zamUlozka === 0)) return [];
const n = (65 - vek) * 12;
if (n <= 0) return [];

