let statniPrispevekMesicni = 0;
if (ulozka >= 500) {
    statniPrispevekMesicni = Math.min(ulozka, 1700) * 0.2;
}

const vkladyReal = Math.round(n * ulozka);
const statniReal = Math.round(n * statniPrispevekMesicni);
const zamestnavatelReal = Math.round(n * zamUlozka);

// 2. Výpočet zhodnocení s úrokem podle věku
