    variables['708e547d-0263-4f29-9d79-751813f6657d'],
    variables['goal_pension'],
    variables['goal_saving_kids'],
    variables['goal_car'],
    variables['goal_savings_reserve'],
    variables['goal_property'],
    variables['goal_other']
];

const inflation = 0.03;
let celkoveVkladySum = 0;
let celkovyZiskSum = 0;

// 2. Logika výpočtu
function calculateGoalData(goal) {
    const targetAmount = Number(goal?.['amount']) || 0;
    const years = Number(goal?.['horizon']) || 0;
    if (targetAmount === 0 || years === 0) return { vklady: 0, zisk: 0 };
    
    const annualReturn = (years <= 3) ? 0.03 : (years <= 7) ? 0.05 : 0.08;
    const realAnnualReturn = (1 + annualReturn) / (1 + inflation) - 1;
    const totalMonths = years * 12;
    
    let monthlyPayment = (totalMonths > 0 && (realAnnualReturn / 12) > 0)
        ? targetAmount * ((realAnnualReturn / 12) / (Math.pow(1 + (realAnnualReturn / 12), totalMonths) - 1))
        : (totalMonths > 0) ? targetAmount / totalMonths : 0;
        
    const totalFutureValue = (totalMonths > 0 && (annualReturn / 12) > 0)
        ? monthlyPayment * ((Math.pow(1 + (annualReturn / 12), totalMonths) - 1) / (annualReturn / 12))
        : monthlyPayment * totalMonths;
        
    const vklady = monthlyPayment * totalMonths;
    return { vklady: vklady, zisk: Math.max(0, totalFutureValue - vklady) };
}

// Spustíme výpočet pro všechny cíle
goals.forEach(goal => {
