        label: 'Zhodnocení',
        data: [proGraf(zhodnoceniReal)],
        backgroundColor: '#007bff', // Modrá
        stack: 'Stack 0',
        borderSkipped: false
    },
    {
        label: 'Státní příspěvky',
        data: [proGraf(statniReal)],
        backgroundColor: '#f05a5a', // Červená
        stack: 'Stack 0',
        borderRadius: { topRight: 15, bottomRight: 15 }, // Zaoblení konce
        borderSkipped: false
    }
];

