        label: 'Vklady',
        data: [Math.round(celkoveVkladySum)], // Hodnota pro první část pruhu
        backgroundColor: '#006B47',
        stack: 'total', // Důležité pro skládání do sebe
        barThickness: 25,
        borderRadius: {
            topLeft: 12,
