const targetAmount = Number(variables['goal_property']?.['amount']) || 0;
const years = Number(variables['goal_property']?.['horizon']) || 0;

// 2. Nastavení parametrů (3% inflace)
const inflation = 0.03;
let annualReturn = 0;

// 3. Výběr výnosu podle horizontu
if (years <= 3) {
    annualReturn = 0.03;
} else if (years <= 7) {
    annualReturn = 0.05;
} else {
    annualReturn = 0.08;
}

// 4. Výpočet reálné úrokové míry (očištěno o inflaci)
const realAnnualReturn = (1 + annualReturn) / (1 + inflation) - 1;
const monthlyRate = realAnnualReturn / 12;
const totalMonths = years * 12;

// 5. Výpočet měsíční úložky
