const mesicniUlozka = variables['80654cb8-53d8-4dc8-81a4-c5fa48398042'];

// Validace - pokud chybí data, vrátíme prázdné pole
if (vek === undefined || vek === null || !mesicniUlozka) {
    return [];
}

// 2. Parametry výpočtu (horizont do 65 let)
const n = (65 - vek) * 12;
const r = 0.07 / 12;
const statniReal = Math.round(n * Math.min(mesicniUlozka * 0.2, 340));
const vkladyReal = Math.round(n * mesicniUlozka);

const p = mesicniUlozka + Math.min(mesicniUlozka * 0.2, 340);
const celkemReal = p * ((Math.pow(1 + r, n) - 1) / r);
const zhodnoceniReal = Math.round(celkemReal - vkladyReal - statniReal);

// 3. Logika pro vizuální relativitu (aby malé části nebyly "neviditelné")
// Celková suma pro výpočet podílů
const sumaVseho = vkladyReal + zhodnoceniReal + statniReal;

// Funkce zajistí, že každý segment zabere aspoň 5 % šířky grafu
const proGraf = (hodnota) => {
    const podil = (hodnota / sumaVseho);
    return podil < 0.05 ? (sumaVseho * 0.05) : hodnota;
};

// 4. Návrat datasetů pro Chart.js
return [
    {
        label: 'Moje příspěvky',
        data: [proGraf(vkladyReal)],
        backgroundColor: '#007d40', // Zelená
        stack: 'Stack 0',
        borderRadius: { topLeft: 15, bottomLeft: 15 }, // Zaoblení startu
        borderSkipped: false
    },
    {
        label: 'Zhodnocení',
        data: [proGraf(zhodnoceniReal)],
        backgroundColor: '#007bff', // Modrá
        stack: 'Stack 0',
        borderSkipped: false
    },
    {
        label: 'Státní příspěvky',
        data: [proGraf(statniReal)],
        backgroundColor: '#f05a5a', // Červená
        stack: 'Stack 0',
        borderRadius: { topRight: 15, bottomRight: 15 }, // Zaoblení konce
        borderSkipped: false
    }
];

