const realAnnualReturn = (1 + annualReturn) / (1 + inflation) - 1;
const monthlyRate = realAnnualReturn / 12;
const totalMonths = years * 12;

// 5. Výpočet měsíční úložky
let monthlyPayment = 0;
if (totalMonths > 0) {
    if (monthlyRate > 0) {
        monthlyPayment = targetAmount * (monthlyRate / (Math.pow(1 + monthlyRate, totalMonths) - 1));
    } else {
        monthlyPayment = targetAmount / totalMonths;
    }
}

// 6. FORMÁTOVÁNÍ NA CZK
return new Intl.NumberFormat('cs-CZ', {
