const r = 0.07 / 12; // měsíční úroková míra (7 % p.a. / 12)
const statniPrispevek = Math.min(mesicniUlozka * 0.2, 340);

// 3. Výpočet celkové naspořené částky (FV)
const p = mesicniUlozka + statniPrispevek;
const celkem = p * ((Math.pow(1 + r, n) - 1) / r);

// 4. Výpočet samotných vkladů (vlastní + státní bez úroků)
const vkladyVlastni = n * mesicniUlozka;
const vkladyStatni = n * statniPrispevek;

// 5. FINÁLNÍ VÝSLEDEK: Zhodnocení (Celkem - co se tam fyzicky vložilo)
const zhodnoceni = celkem - vkladyVlastni - vkladyStatni;

// 6. Formátování výsledku
